{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Accounts List",
  "description": "A list of commerce accounts generated by AI.",
  "type": "object",
  "properties": {
    "accounts": {
      "type": "array",
      "description": "An array of generated account objects.",
      "items": {
        "type": "object",
        "properties": {
          "name": {
            "description": "The name of the account.",
            "type": "string"
          },
          "description": {
            "description": "A description for the account.",
            "type": "string"
          },
          "type": {
            "description": "The type of account, e.g., 'business'.",
            "type": "string"
          },
          "taxId": {
            "description": "The tax ID for the account.",
            "type": "string"
          },
          "externalReferenceCode": {
            "description": "A unique identifier for the account.",
            "type": "string"
          },
          "accountContactInformation": {
            "description": "Contact information for the account.",
            "type": "object",
            "properties": {
              "emailAddresses": {
                "type": "array",
                "description": "A list of email addresses for the account.",
                "items": {
                  "type": "object",
                  "properties": {
                    "emailAddress": {
                      "description": "The email address.",
                      "type": "string",
                      "format": "email"
                    },
                    "primary": {
                      "description": "Whether this is the primary email address.",
                      "type": "boolean"
                    },
                    "type": {
                      "description": "The type of email address (e.g., 'email-address').",
                      "type": "string"
                    }
                  },
                  "required": ["emailAddress", "primary", "type"]
                }
              },
              "domains": {
                "description": "A list of domains associated with the account.",
                "type": "array",
                "items": {
                  "type": "string",
                  "format": "hostname"
                }
              }
            },
            "required": ["emailAddresses"]
          }
        },
        "required": [
          "name",
          "type",
          "externalReferenceCode",
          "accountContactInformation"
        ]
      }
    }
  },
  "required": ["accounts"]
}
